def seed():
    client = get_client()
    total = len(PROFILES)

    for i, profile_data in enumerate(PROFILES, 1):
        name = profile_data["name"]
        print(f"Seeding profile {i}/{total}: {name}...")

        email = profile_data.pop("_email")

        # Create user in auth.users via admin API
        try:
            auth_response = client.auth.admin.create_user({
                "email": email,
                "password": "SeedPassword123!",
                "email_confirm": True,
            })
            user_id = str(auth_response.user.id)
        except Exception as e:
            print(f"  ! Auth user creation failed for {name}: {e} — skipping")
            continue

        # Insert into our users table with the same id
        try:
            client.table("users").insert({"id": user_id, "email": email}).execute()
        except Exception as e:
            print(f"  ! Users table insert failed for {name}: {e} — skipping")
            continue

        # Build profile payload
        profile_payload = {**profile_data, "user_id": user_id}

        # Insert into profiles table
        try:
            result = client.table("profiles").insert(profile_payload).execute()
            if not result.data:
                print(f"  ! Profile insert returned no data for {name} — skipping embedding")
                continue
            saved_profile = result.data[0]
        except Exception as e:
            print(f"  ! Profile insert failed for {name}: {e} — skipping")
            continue

        # Generate and store embedding
        try:
            embedding = generate_embedding(saved_profile)
            store_embedding(user_id, embedding)
            print(f"  ✓ Embedded: {name}")
        except Exception as e:
            print(f"  ! Embedding failed for {name}: {e}")

    print(f"\nDone. {total} profiles seeded and embedded.")


if __name__ == "__main__":
    seed()
